import { PrismaClient } from "@prisma/client";

const globalForPrisma = globalThis as unknown as {
  prisma: PrismaClient | undefined;
};

export const prisma =
  globalForPrisma.prisma ??
  new PrismaClient({
    log: process.env.NODE_ENV === "development" ? ["error", "warn"] : ["error"],
  });

if (process.env.NODE_ENV !== "production") globalForPrisma.prisma = prisma;

import { type ClassValue, clsx } from "clsx";
import { twMerge } from "tailwind-merge";

export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs));
}

export function formatCurrency(value: number) {
  return new Intl.NumberFormat("en-US", {
    minimumFractionDigits: 2,
    maximumFractionDigits: 2,
  }).format(value);
}

export function formatDate(date: Date | string) {
  return new Intl.DateTimeFormat("en-CA").format(new Date(date));
}

export function toDateInputValue(date: Date | string) {
  return formatDate(date);
}

export function startOfDay(date: Date) {
  const d = new Date(date);
  d.setHours(0, 0, 0, 0);
  return d;
}

export function endOfDay(date: Date) {
  const d = new Date(date);
  d.setHours(23, 59, 59, 999);
  return d;
}

import { Role } from "@prisma/client";
import { getServerSession } from "next-auth";
import { authOptions } from "@/lib/auth-options";

export { authOptions };

export async function getSession() {
  return getServerSession(authOptions);
}

export async function requireSession() {
  const session = await getSession();
  if (!session?.user?.id) {
    throw new Error("Unauthorized");
  }
  return session;
}

export function hasRole(
  role: Role | undefined,
  allowed: Role | Role[]
): boolean {
  if (!role) return false;
  const roles = Array.isArray(allowed) ? allowed : [allowed];
  return roles.includes(role);
}

export function dashboardPathForRole(role: Role) {
  switch (role) {
    case Role.SUPER_ADMIN:
      return "/dashboard/super-admin";
    case Role.ADMIN:
      return "/dashboard/admin";
    case Role.USER:
      return "/dashboard/user";
    default:
      return "/login";
  }
}

import { Role } from "@prisma/client";
import bcrypt from "bcryptjs";
import type { NextAuthOptions } from "next-auth";
import CredentialsProvider from "next-auth/providers/credentials";
import { prisma } from "@/lib/prisma";

export const authOptions: NextAuthOptions = {
  session: { strategy: "jwt", maxAge: 60 * 60 * 24 * 7 },
  pages: { signIn: "/login" },
  providers: [
    CredentialsProvider({
      name: "credentials",
      credentials: {
        username: { label: "Username", type: "text" },
        password: { label: "Password", type: "password" },
      },
      async authorize(credentials) {
        if (!credentials?.username || !credentials?.password) return null;

        const user = await prisma.user.findUnique({
          where: { username: credentials.username.trim().toLowerCase() },
        });
        if (!user) return null;

        const valid = await bcrypt.compare(
          credentials.password,
          user.passwordHash
        );
        if (!valid) return null;

        return {
          id: user.id,
          name: user.username,
          email: user.username,
          role: user.role,
          canEditEntries: user.canEditEntries,
        };
      },
    }),
  ],
  callbacks: {
    async jwt({ token, user, trigger, session }) {
      if (user) {
        token.id = user.id;
        token.role = (user as { role: Role }).role;
        token.canEditEntries = (user as { canEditEntries: boolean })
          .canEditEntries;
        token.username = user.name ?? "";
      }
      if (trigger === "update" && session) {
        token.canEditEntries = session.canEditEntries;
      }
      return token;
    },
    async session({ session, token }) {
      if (session.user) {
        session.user.id = token.id as string;
        session.user.role = token.role as Role;
        session.user.canEditEntries = token.canEditEntries as boolean;
        session.user.username = token.username as string;
      }
      return session;
    },
  },
};

import { z } from "zod";

export const loginSchema = z.object({
  username: z.string().min(2, "Username is required"),
  password: z.string().min(6, "Password must be at least 6 characters"),
});

export const createUserSchema = z.object({
  username: z
    .string()
    .min(3, "Username must be at least 3 characters")
    .max(32)
    .regex(/^[a-z0-9_]+$/, "Lowercase letters, numbers, underscore only"),
  password: z.string().min(6, "Password must be at least 6 characters"),
  role: z.enum(["ADMIN", "USER"]),
});

export const entrySchema = z.object({
  date: z.string().min(1, "Date is required"),
  system: z.coerce.number().finite(),
  online: z.coerce.number().finite(),
  number: z.coerce.number().finite().optional().default(0),
  bonus: z.coerce.number().finite(),
  win: z.coerce.number().finite(),
  cash: z.coerce.number().finite(),
  note: z.string().max(2000).optional().nullable(),
});

export const messageSchema = z.object({
  content: z.string().min(1, "Message cannot be empty").max(5000),
});

export type EntryInput = z.infer<typeof entrySchema>;

import { Role } from "@prisma/client";
import { getServerSession } from "next-auth";
import { NextResponse } from "next/server";
import { authOptions } from "@/lib/auth-options";
import { hasRole } from "@/lib/auth";

export async function getApiSession() {
  return getServerSession(authOptions);
}

export function unauthorized() {
  return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
}

export function forbidden(message = "Forbidden") {
  return NextResponse.json({ error: message }, { status: 403 });
}

export function badRequest(message: string) {
  return NextResponse.json({ error: message }, { status: 400 });
}

export async function requireApiRole(allowed: Role | Role[]) {
  const session = await getApiSession();
  if (!session?.user?.id) return { error: unauthorized() } as const;
  if (!hasRole(session.user.role, allowed)) {
    return { error: forbidden() } as const;
  }
  return { session } as const;
}

