import { PrismaClient, Role } from "@prisma/client";
import bcrypt from "bcryptjs";

const prisma = new PrismaClient();

async function main() {
  const username = (
    process.env.SEED_SUPER_ADMIN_USERNAME ?? "superadmin"
  ).toLowerCase();
  const password = process.env.SEED_SUPER_ADMIN_PASSWORD ?? "SuperAdmin123!";

  const existing = await prisma.user.findUnique({ where: { username } });
  if (existing) {
    console.log(`Super admin "${username}" already exists. Skipping seed.`);
    return;
  }

  const passwordHash = await bcrypt.hash(password, 12);
  await prisma.user.create({
    data: {
      username,
      passwordHash,
      role: Role.SUPER_ADMIN,
      canEditEntries: true,
    },
  });

  console.log("Seed complete.");
  console.log(`Super Admin username: ${username}`);
  console.log(`Super Admin password: ${password}`);
  console.log("Change the password after first login in production.");
}

main()
  .catch((e) => {
    console.error(e);
    process.exit(1);
  })
  .finally(() => prisma.$disconnect());

import { Role } from "@prisma/client";
import { withAuth } from "next-auth/middleware";
import { NextResponse } from "next/server";
import { dashboardPathForRole } from "@/lib/auth";

export default withAuth(
  function middleware(req) {
    const token = req.nextauth.token;
    const path = req.nextUrl.pathname;

    if (!token) {
      return NextResponse.redirect(new URL("/login", req.url));
    }

    const role = token.role as Role;
    const home = dashboardPathForRole(role);

    // Redirect generic /dashboard to role-specific dashboard
    if (path === "/dashboard") {
      return NextResponse.redirect(new URL(home, req.url));
    }

    // Role-based route protection
    if (path.startsWith("/dashboard/super-admin") && role !== Role.SUPER_ADMIN) {
      return NextResponse.redirect(new URL(home, req.url));
    }
    if (path.startsWith("/dashboard/admin")) {
      if (role !== Role.ADMIN && role !== Role.SUPER_ADMIN) {
        return NextResponse.redirect(new URL(home, req.url));
      }
    }
    if (path.startsWith("/dashboard/user") && role !== Role.USER) {
      return NextResponse.redirect(new URL(home, req.url));
    }

    return NextResponse.next();
  },
  {
    callbacks: {
      authorized: ({ token, req }) => {
        if (req.nextUrl.pathname.startsWith("/login")) return true;
        return !!token;
      },
    },
  }
);

