import { Role } from "@prisma/client";
import bcrypt from "bcryptjs";
import { NextRequest, NextResponse } from "next/server";
import {
  badRequest,
  forbidden,
  getApiSession,
  requireApiRole,
  unauthorized,
} from "@/lib/api-auth";
import { prisma } from "@/lib/prisma";
import { createUserSchema } from "@/lib/validations";

export async function GET(req: NextRequest) {
  const session = await getApiSession();
  if (!session?.user?.id) return unauthorized();

  const { searchParams } = new URL(req.url);
  const search = searchParams.get("search")?.toLowerCase();
  const roleFilter = searchParams.get("role") as Role | null;

  let where: {
    role?: Role | { in: Role[] };
    createdById?: string | null;
    username?: { contains: string };
  } = {};

  if (session.user.role === Role.SUPER_ADMIN) {
    const roles = roleFilter
      ? [roleFilter]
      : [Role.ADMIN, Role.USER];
    where.role = { in: roles };
    if (search) {
      where = { ...where, username: { contains: search } };
    }
  } else if (session.user.role === Role.ADMIN) {
    where = {
      role: Role.USER,
      createdById: session.user.id,
    };
    if (search) {
      where.username = { contains: search };
    }
  } else {
    return forbidden();
  }

  const users = await prisma.user.findMany({
    where,
    select: {
      id: true,
      username: true,
      role: true,
      canEditEntries: true,
      createdAt: true,
      createdById: true,
      _count: { select: { entries: true } },
    },
    orderBy: { createdAt: "desc" },
  });

  return NextResponse.json(users);
}

export async function POST(req: NextRequest) {
  const session = await getApiSession();
  if (!session?.user?.id) return unauthorized();

  const body = await req.json();
  const parsed = createUserSchema.safeParse(body);
  if (!parsed.success) {
    return badRequest(parsed.error.errors[0]?.message ?? "Invalid data");
  }

  const { username, password, role } = parsed.data;

  if (session.user.role === Role.ADMIN && role !== Role.USER) {
    return forbidden("Admins can only create users");
  }
  if (session.user.role !== Role.SUPER_ADMIN && session.user.role !== Role.ADMIN) {
    return forbidden();
  }
  if (session.user.role === Role.ADMIN && role === Role.ADMIN) {
    return forbidden();
  }
  if (role === Role.ADMIN && session.user.role !== Role.SUPER_ADMIN) {
    return forbidden("Only super admin can create admins");
  }

  const normalizedUsername = username.toLowerCase();
  const exists = await prisma.user.findUnique({
    where: { username: normalizedUsername },
  });
  if (exists) return badRequest("Username already exists");

  const passwordHash = await bcrypt.hash(password, 12);
  const user = await prisma.user.create({
    data: {
      username: normalizedUsername,
      passwordHash,
      role: role as Role,
      createdById:
        session.user.role === Role.SUPER_ADMIN && role === Role.ADMIN
          ? null
          : session.user.id,
      canEditEntries: false,
    },
    select: {
      id: true,
      username: true,
      role: true,
      canEditEntries: true,
      createdAt: true,
    },
  });

  return NextResponse.json(user, { status: 201 });
}

import { Role } from "@prisma/client";
import bcrypt from "bcryptjs";
import { NextRequest, NextResponse } from "next/server";
import {
  badRequest,
  forbidden,
  getApiSession,
  unauthorized,
} from "@/lib/api-auth";
import { prisma } from "@/lib/prisma";

type Params = { params: Promise<{ id: string }> };

export async function PATCH(req: NextRequest, { params }: Params) {
  const session = await getApiSession();
  if (!session?.user?.id) return unauthorized();

  const { id } = await params;
  const target = await prisma.user.findUnique({ where: { id } });
  if (!target) {
    return NextResponse.json({ error: "Not found" }, { status: 404 });
  }

  const body = await req.json();

  // Toggle canEditEntries (admin for their users, super admin for anyone)
  if (typeof body.canEditEntries === "boolean") {
    if (session.user.role === Role.ADMIN) {
      if (target.createdById !== session.user.id || target.role !== Role.USER) {
        return forbidden();
      }
    } else if (session.user.role !== Role.SUPER_ADMIN) {
      return forbidden();
    }

    const updated = await prisma.user.update({
      where: { id },
      data: { canEditEntries: body.canEditEntries },
      select: {
        id: true,
        username: true,
        canEditEntries: true,
      },
    });
    return NextResponse.json(updated);
  }

  // Reset password (super admin or creator admin)
  if (body.password && typeof body.password === "string") {
    if (body.password.length < 6) {
      return badRequest("Password must be at least 6 characters");
    }
    const canReset =
      session.user.role === Role.SUPER_ADMIN ||
      (session.user.role === Role.ADMIN &&
        target.createdById === session.user.id);
    if (!canReset) return forbidden();

    const passwordHash = await bcrypt.hash(body.password, 12);
    await prisma.user.update({
      where: { id },
      data: { passwordHash },
    });
    return NextResponse.json({ success: true });
  }

  return badRequest("No valid fields to update");
}

export async function DELETE(_req: NextRequest, { params }: Params) {
  const session = await getApiSession();
  if (!session?.user?.id) return unauthorized();

  const { id } = await params;
  if (id === session.user.id) {
    return badRequest("Cannot delete your own account");
  }

  const target = await prisma.user.findUnique({ where: { id } });
  if (!target) {
    return NextResponse.json({ error: "Not found" }, { status: 404 });
  }

  if (session.user.role === Role.SUPER_ADMIN) {
    if (target.role === Role.SUPER_ADMIN) {
      return forbidden("Cannot delete super admin");
    }
  } else if (session.user.role === Role.ADMIN) {
    if (target.createdById !== session.user.id || target.role !== Role.USER) {
      return forbidden();
    }
  } else {
    return forbidden();
  }

  await prisma.user.delete({ where: { id } });
  return NextResponse.json({ success: true });
}

import { Role } from "@prisma/client";
import { NextRequest, NextResponse } from "next/server";
import {
  badRequest,
  forbidden,
  getApiSession,
  unauthorized,
} from "@/lib/api-auth";
import { prisma } from "@/lib/prisma";
import { messageSchema } from "@/lib/validations";

export async function GET() {
  const session = await getApiSession();
  if (!session?.user?.id) return unauthorized();

  if (session.user.role === Role.SUPER_ADMIN) {
    const messages = await prisma.message.findMany({
      include: {
        admin: { select: { id: true, username: true } },
      },
      orderBy: { createdAt: "desc" },
    });
    const unreadCount = await prisma.message.count({ where: { read: false } });
    return NextResponse.json({ messages, unreadCount });
  }

  if (session.user.role === Role.ADMIN) {
    const messages = await prisma.message.findMany({
      where: { adminId: session.user.id },
      orderBy: { createdAt: "desc" },
    });
    return NextResponse.json({ messages, unreadCount: 0 });
  }

  return forbidden();
}

export async function POST(req: NextRequest) {
  const session = await getApiSession();
  if (!session?.user?.id) return unauthorized();
  if (session.user.role !== Role.ADMIN) {
    return forbidden("Only admins can send messages to super admin");
  }

  const body = await req.json();
  const parsed = messageSchema.safeParse(body);
  if (!parsed.success) {
    return badRequest(parsed.error.errors[0]?.message ?? "Invalid message");
  }

  const message = await prisma.message.create({
    data: {
      content: parsed.data.content.trim(),
      adminId: session.user.id,
    },
    include: {
      admin: { select: { username: true } },
    },
  });

  return NextResponse.json(message, { status: 201 });
}

import { Role } from "@prisma/client";
import { NextRequest, NextResponse } from "next/server";
import { forbidden, getApiSession, unauthorized } from "@/lib/api-auth";
import { prisma } from "@/lib/prisma";

type Params = { params: Promise<{ id: string }> };

export async function PATCH(_req: NextRequest, { params }: Params) {
  const session = await getApiSession();
  if (!session?.user?.id) return unauthorized();
  if (session.user.role !== Role.SUPER_ADMIN) return forbidden();

  const { id } = await params;
  const message = await prisma.message.update({
    where: { id },
    data: { read: true },
  });

  return NextResponse.json(message);
}

import { Role } from "@prisma/client";
import { NextRequest, NextResponse } from "next/server";
import { forbidden, getApiSession, unauthorized } from "@/lib/api-auth";
import { prisma } from "@/lib/prisma";
import { endOfDay, startOfDay } from "@/lib/utils";

export async function GET(req: NextRequest) {
  const session = await getApiSession();
  if (!session?.user?.id) return unauthorized();

  const { searchParams } = new URL(req.url);
  const userId = searchParams.get("userId");
  const dateFrom = searchParams.get("dateFrom");
  const dateTo = searchParams.get("dateTo");

  const entryWhere: {
    userId?: string | { in: string[] };
    date?: { gte?: Date; lte?: Date };
  } = {};

  if (session.user.role === Role.USER) {
    entryWhere.userId = session.user.id;
  } else if (session.user.role === Role.ADMIN) {
    const myUsers = await prisma.user.findMany({
      where: { createdById: session.user.id, role: Role.USER },
      select: { id: true },
    });
    const ids = myUsers.map((u) => u.id);
    entryWhere.userId = userId && ids.includes(userId) ? userId : { in: ids };
  } else if (session.user.role === Role.SUPER_ADMIN) {
    if (userId) entryWhere.userId = userId;
  } else {
    return forbidden();
  }

  if (dateFrom || dateTo) {
    entryWhere.date = {};
    if (dateFrom) entryWhere.date.gte = startOfDay(new Date(dateFrom));
    if (dateTo) entryWhere.date.lte = endOfDay(new Date(dateTo));
  }

  const [aggregate, entryCount, userCount, unreadMessages] = await Promise.all([
    prisma.entry.aggregate({
      where: entryWhere,
      _sum: {
        system: true,
        online: true,
        number: true,
        bonus: true,
        win: true,
        cash: true,
      },
    }),
    prisma.entry.count({ where: entryWhere }),
    session.user.role === Role.SUPER_ADMIN
      ? prisma.user.count({ where: { role: { in: [Role.ADMIN, Role.USER] } } })
      : session.user.role === Role.ADMIN
        ? prisma.user.count({
            where: { createdById: session.user.id, role: Role.USER },
          })
        : Promise.resolve(1),
    session.user.role === Role.SUPER_ADMIN
      ? prisma.message.count({ where: { read: false } })
      : Promise.resolve(0),
  ]);

  return NextResponse.json({
    entryCount,
    userCount,
    unreadMessages,
    totals: {
      system: aggregate._sum.system ?? 0,
      online: aggregate._sum.online ?? 0,
      number: aggregate._sum.number ?? 0,
      bonus: aggregate._sum.bonus ?? 0,
      win: aggregate._sum.win ?? 0,
      cash: aggregate._sum.cash ?? 0,
    },
  });
}

