"use client";

import { formatCurrency } from "@/lib/utils";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";

interface Stats {
  entryCount: number;
  userCount?: number;
  unreadMessages?: number;
  totals: {
    system: number;
    online: number;
    number: number;
    bonus: number;
    win: number;
    cash: number;
  };
}

export function StatsCards({ stats }: { stats: Stats }) {
  const cards = [
    { label: "Total Entries", value: stats.entryCount.toString() },
    ...(stats.userCount !== undefined
      ? [{ label: "Users", value: stats.userCount.toString() }]
      : []),
    ...(stats.unreadMessages !== undefined && stats.unreadMessages > 0
      ? [{ label: "Unread Messages", value: stats.unreadMessages.toString() }]
      : []),
    { label: "Total Cash", value: formatCurrency(stats.totals.cash) },
    { label: "Total Win", value: formatCurrency(stats.totals.win) },
    { label: "Total Bonus", value: formatCurrency(stats.totals.bonus) },
  ];

  return (
    <div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4">
      {cards.map((c) => (
        <Card key={c.label}>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium text-muted-foreground">
              {c.label}
            </CardTitle>
          </CardHeader>
          <CardContent>
            <p className="text-2xl font-bold">{c.value}</p>
          </CardContent>
        </Card>
      ))}
    </motionless>
  );
}

"use client";

import { useState } from "react";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { Loader2 } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { entrySchema, type EntryInput } from "@/lib/validations";
import { toDateInputValue } from "@/lib/utils";
import { useAppStore } from "@/store/use-app-store";

export interface EntryRecord {
  id: string;
  date: string;
  system: number;
  online: number;
  number: number;
  bonus: number;
  win: number;
  cash: number;
  note: string | null;
}

interface EntryFormProps {
  initial?: EntryRecord;
  onSuccess: () => void;
  onCancel?: () => void;
}

export function EntryForm({ initial, onSuccess, onCancel }: EntryFormProps) {
  const [loading, setLoading] = useState(false);
  const addToast = useAppStore((s) => s.addToast);

  const {
    register,
    handleSubmit,
    formState: { errors },
  } = useForm<EntryInput>({
    resolver: zodResolver(entrySchema),
    defaultValues: initial
      ? {
          date: toDateInputValue(initial.date),
          system: initial.system,
          online: initial.online,
          number: initial.number,
          bonus: initial.bonus,
          win: initial.win,
          cash: initial.cash,
          note: initial.note ?? "",
        }
      : {
          date: toDateInputValue(new Date()),
          system: 0,
          online: 0,
          number: 0,
          bonus: 0,
          win: 0,
          cash: 0,
          note: "",
        },
  });

  const onSubmit = async (data: EntryInput) => {
    setLoading(true);
    try {
      const url = initial ? `/api/entries/${initial.id}` : "/api/entries";
      const method = initial ? "PATCH" : "POST";
      const res = await fetch(url, {
        method,
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          ...data,
          number: data.number ?? 0,
        }),
      });
      const json = await res.json();
      if (!res.ok) throw new Error(json.error ?? "Failed to save");
      addToast({
        type: "success",
        title: initial ? "Entry updated" : "Entry submitted",
      });
      onSuccess();
    } catch (e) {
      addToast({
        type: "error",
        title: e instanceof Error ? e.message : "Something went wrong",
      });
    } finally {
      setLoading(false);
    }
  };

  return (
    <Card>
      <CardHeader>
        <CardTitle>{initial ? "Edit Entry" : "New Entry"}</CardTitle>
      </CardHeader>
      <CardContent>
        <form onSubmit={handleSubmit(onSubmit)} className="space-y-4">
          <motionless className="grid gap-4 sm:grid-cols-2 lg:grid-cols-3">
            <div className="space-y-2">
              <Label htmlFor="date">Date</Label>
              <Input id="date" type="date" {...register("date")} />
              {errors.date && (
                <p className="text-xs text-destructive">{errors.date.message}</p>
              )}
            </div>
            {(
              [
                ["system", "System"],
                ["online", "Online"],
                ["number", "Number"],
                ["bonus", "Bonus"],
                ["win", "Win"],
                ["cash", "Cash"],
              ] as const
            ).map(([name, label]) => (
              <div key={name} className="space-y-2">
                <Label htmlFor={name}>{label}</Label>
                <Input
                  id={name}
                  type="number"
                  step="any"
                  {...register(name, { valueAsNumber: true })}
                />
                {errors[name] && (
                  <p className="text-xs text-destructive">
                    {errors[name]?.message}
                  </p>
                )}
              </div>
            ))}
          </motionless>
          <div className="space-y-2">
            <Label htmlFor="note">Note (optional)</Label>
            <Textarea id="note" rows={3} {...register("note")} />
          </div>
          <div className="flex gap-2">
            <Button type="submit" disabled={loading}>
              {loading && <Loader2 className="h-4 w-4 animate-spin" />}
              {initial ? "Update" : "Submit"}
            </Button>
            {onCancel && (
              <Button type="button" variant="outline" onClick={onCancel}>
                Cancel
              </Button>
            )}
          </div>
        </form>
      </CardContent>
    </Card>
  );
}

"use client";

import { Pencil } from "lucide-react";
import { Button } from "@/components/ui/button";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { formatCurrency, formatDate } from "@/lib/utils";
import type { EntryRecord } from "./entry-form";

export function EntriesTable({
  entries,
  canEdit,
  onEdit,
}: {
  entries: (EntryRecord & { user?: { username: string } })[];
  canEdit?: boolean;
  onEdit?: (entry: EntryRecord) => void;
}) {
  if (!entries.length) {
    return (
      <p className="text-center text-muted-foreground py-8">No entries found.</p>
    );
  }

  return (
    <div className="rounded-lg border border-border overflow-hidden">
      <Table>
        <TableHeader>
          <TableRow>
            <TableHead>Date</TableHead>
            {entries[0]?.user && <TableHead>User</TableHead>}
            <TableHead>System</TableHead>
            <TableHead>Online</TableHead>
            <TableHead>Number</TableHead>
            <TableHead>Bonus</TableHead>
            <TableHead>Win</TableHead>
            <TableHead>Cash</TableHead>
            <TableHead>Note</TableHead>
            {canEdit && <TableHead className="w-20" />}
          </TableRow>
        </TableHeader>
        <TableBody>
          {entries.map((e) => (
            <TableRow key={e.id}>
              <TableCell>{formatDate(e.date)}</TableCell>
              {e.user && <TableCell>{e.user.username}</TableCell>}
              <TableCell>{formatCurrency(e.system)}</TableCell>
              <TableCell>{formatCurrency(e.online)}</TableCell>
              <TableCell>{formatCurrency(e.number)}</TableCell>
              <TableCell>{formatCurrency(e.bonus)}</TableCell>
              <TableCell>{formatCurrency(e.win)}</TableCell>
              <TableCell className="font-medium">
                {formatCurrency(e.cash)}
              </TableCell>
              <TableCell className="max-w-[120px] truncate text-muted-foreground">
                {e.note || "—"}
              </TableCell>
              {canEdit && (
                <TableCell>
                  <Button
                    variant="ghost"
                    size="icon"
                    onClick={() => onEdit?.(e)}
                    title="Edit entry"
                  >
                    <Pencil className="h-4 w-4" />
                  </Button>
                </TableCell>
              )}
            </TableRow>
          ))}
        </TableBody>
      </Table>
    </div>
  );
}

