"use client";

import { useCallback, useEffect, useState } from "react";
import { useSession } from "next-auth/react";
import { DashboardShell, userNav } from "@/components/layout/dashboard-shell";
import { EntryForm, type EntryRecord } from "@/components/entries/entry-form";
import { EntriesTable } from "@/components/entries/entries-table";
import { StatsCards } from "@/components/stats-cards";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";

export default function UserDashboardPage() {
  const { data: session, update } = useSession();
  const [entries, setEntries] = useState<EntryRecord[]>([]);
  const [stats, setStats] = useState<{
    entryCount: number;
    totals: { cash: number; win: number; bonus: number; system: number; online: number; number: number };
  } | null>(null);
  const [editing, setEditing] = useState<EntryRecord | null>(null);
  const [loading, setLoading] = useState(true);

  const load = useCallback(async () => {
    const [entriesRes, statsRes] = await Promise.all([
      fetch("/api/entries"),
      fetch("/api/stats"),
    ]);
    const entriesData = await entriesRes.json();
    const statsData = await statsRes.json();
    setEntries(entriesData);
    setStats(statsData);
    setLoading(false);
  }, []);

  useEffect(() => {
    load();
  }, [load]);

  // Refresh session canEdit from server periodically
  useEffect(() => {
    update();
  }, [update]);

  const canEdit = session?.user?.canEditEntries ?? false;

  return (
    <DashboardShell navItems={userNav} title="My Dashboard">
      {stats && <StatsCards stats={{ ...stats, userCount: undefined }} />}

      {!editing ? (
        <EntryForm onSuccess={load} />
      ) : (
        <EntryForm
          initial={editing}
          onSuccess={() => {
            setEditing(null);
            load();
          }}
          onCancel={() => setEditing(null)}
        />
      )}

      <Card className="mt-6">
        <CardHeader>
          <CardTitle>Entry History</CardTitle>
          {!canEdit && (
            <p className="text-sm text-muted-foreground">
              Editing is disabled. Contact your admin to enable edits.
            </p>
          )}
        </CardHeader>
        <CardContent>
          {loading ? (
            <p className="text-muted-foreground">Loading...</p>
          ) : (
            <EntriesTable
              entries={entries}
              canEdit={canEdit}
              onEdit={(e) => setEditing(e)}
            />
          )}
        </CardContent>
      </Card>
    </DashboardShell>
  );
}

"use client";

import { useCallback, useEffect, useState } from "react";
import { useRouter } from "next/navigation";
import { Loader2, Plus, Trash2 } from "lucide-react";
import { DashboardShell, adminNav } from "@/components/layout/dashboard-shell";
import { StatsCards } from "@/components/stats-cards";
import { EntriesTable } from "@/components/entries/entries-table";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Switch } from "@/components/ui/switch";
import {
  Card,
  CardContent,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { useAppStore } from "@/store/use-app-store";
import type { EntryRecord } from "@/components/entries/entry-form";

interface ManagedUser {
  id: string;
  username: string;
  canEditEntries: boolean;
  _count: { entries: number };
}

export default function AdminDashboardPage() {
  const router = useRouter();
  const addToast = useAppStore((s) => s.addToast);
  const [users, setUsers] = useState<ManagedUser[]>([]);
  const [selectedUserId, setSelectedUserId] = useState<string | null>(null);
  const [entries, setEntries] = useState<EntryRecord[]>([]);
  const [stats, setStats] = useState<Record<string, unknown> | null>(null);
  const [search, setSearch] = useState("");
  const [date, setDate] = useState("");
  const [dateFrom, setDateFrom] = useState("");
  const [dateTo, setDateTo] = useState("");
  const [showCreate, setShowCreate] = useState(false);
  const [newUsername, setNewUsername] = useState("");
  const [newPassword, setNewPassword] = useState("");
  const [creating, setCreating] = useState(false);

  const loadUsers = useCallback(async () => {
    const q = search ? `?search=${encodeURIComponent(search)}` : "";
    const res = await fetch(`/api/users${q}`);
    setUsers(await res.json());
  }, [search]);

  const loadEntries = useCallback(async () => {
    const params = new URLSearchParams();
    if (selectedUserId) params.set("userId", selectedUserId);
    if (date) params.set("date", date);
    if (dateFrom) params.set("dateFrom", dateFrom);
    if (dateTo) params.set("dateTo", dateTo);
    const [entriesRes, statsRes] = await Promise.all([
      fetch(`/api/entries?${params}`),
      fetch(`/api/stats?${params}`),
    ]);
    setEntries(await entriesRes.json());
    setStats(await statsRes.json());
  }, [selectedUserId, date, dateFrom, dateTo]);

  useEffect(() => {
    loadUsers();
  }, [loadUsers]);

  useEffect(() => {
    loadEntries();
  }, [loadEntries]);

  const toggleEdit = async (userId: string, value: boolean) => {
    const res = await fetch(`/api/users/${userId}`, {
      method: "PATCH",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ canEditEntries: value }),
    });
    if (res.ok) {
      addToast({ type: "success", title: "Edit permission updated" });
      loadUsers();
    }
  };

  const createUser = async (e: React.FormEvent) => {
    e.preventDefault();
    setCreating(true);
    const res = await fetch("/api/users", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        username: newUsername,
        password: newPassword,
        role: "USER",
      }),
    });
    setCreating(false);
    const json = await res.json();
    if (!res.ok) {
      addToast({ type: "error", title: json.error ?? "Failed" });
      return;
    }
    addToast({ type: "success", title: "User created" });
    setShowCreate(false);
    setNewUsername("");
    setNewPassword("");
    loadUsers();
  };

  const deleteUser = async (id: string) => {
    if (!confirm("Delete this user and all their data?")) return;
    const res = await fetch(`/api/users/${id}`, { method: "DELETE" });
    if (res.ok) {
      addToast({ type: "success", title: "User deleted" });
      if (selectedUserId === id) setSelectedUserId(null);
      loadUsers();
      loadEntries();
    }
  };

  return (
    <DashboardShell navItems={adminNav} title="Admin Dashboard">
      {stats && (
        <StatsCards
          stats={stats as Parameters<typeof StatsCards>[0]["stats"]}
        />
      )}

      <Card className="mb-6">
        <CardHeader className="flex flex-row items-center justify-between">
          <CardTitle>My Users</CardTitle>
          <Button size="sm" onClick={() => setShowCreate(!showCreate)}>
            <Plus className="h-4 w-4 mr-1" />
            Create User
          </Button>
        </CardHeader>
        <CardContent className="space-y-4">
          {showCreate && (
            <form
              onSubmit={createUser}
              className="grid gap-3 sm:grid-cols-3 border rounded-lg p-4"
            >
              <div>
                <Label>Username</Label>
                <Input
                  value={newUsername}
                  onChange={(e) => setNewUsername(e.target.value)}
                  required
                />
              </div>
              <div>
                <Label>Password</Label>
                <Input
                  type="password"
                  value={newPassword}
                  onChange={(e) => setNewPassword(e.target.value)}
                  required
                />
              </div>
              <div className="flex items-end">
                <Button type="submit" disabled={creating}>
