import { dirname } from "path";
import { fileURLToPath } from "url";
import { FlatCompat } from "@eslint/eslintrc";

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);

const compat = new FlatCompat({ baseDirectory: __dirname });

export default [...compat.extends("next/core-web-vitals")];

/** Minimal solid-color PNG icons for PWA (run: node scripts/generate-icons.mjs) */
import { writeFileSync, mkdirSync } from "fs";
import { join, dirname } from "path";
import { fileURLToPath } from "url";
import zlib from "zlib";

const __dirname = dirname(fileURLToPath(import.meta.url));
const outDir = join(__dirname, "..", "public", "icons");
mkdirSync(outDir, { recursive: true });

function crc32(buf) {
  let c = ~0;
  for (let i = 0; i < buf.length; i++) {
    c ^= buf[i];
    for (let k = 0; k < 8; k++) c = c & 1 ? 0xedb88320 ^ (c >>> 1) : c >>> 1;
  }
  return ~c >>> 0;
}

function chunk(type, data) {
  const len = Buffer.alloc(4);
  len.writeUInt32BE(data.length);
  const typeBuf = Buffer.from(type);
  const crcBuf = Buffer.alloc(4);
  crcBuf.writeUInt32BE(crc32(Buffer.concat([typeBuf, data])));
  return Buffer.concat([len, typeBuf, data, crcBuf]);
}

function png(size, r, g, b) {
  const signature = Buffer.from([137, 80, 78, 71, 13, 10, 26, 10]);
  const ihdr = Buffer.alloc(13);
  ihdr.writeUInt32BE(size, 0);
  ihdr.writeUInt32BE(size, 4);
  ihdr[8] = 8;
  ihdr[9] = 2;
  const row = Buffer.alloc(1 + size * 3);
  row[0] = 0;
  for (let x = 0; x < size; x++) {
    const o = 1 + x * 3;
    row[o] = r;
    row[o + 1] = g;
    row[o + 2] = b;
  }
  const raw = Buffer.concat(Array(size).fill(row));
  const compressed = zlib.deflateSync(raw);
  return Buffer.concat([
    signature,
    chunk("IHDR", ihdr),
    chunk("IDAT", compressed),
    chunk("IEND", Buffer.alloc(0)),
  ]);
}

// Indigo #6366f1
for (const size of [192, 512]) {
  writeFileSync(join(outDir, `icon-${size}.png`), png(size, 99, 102, 241));
}
console.log("Generated public/icons/icon-192.png and icon-512.png");

/** Edge-safe helpers (no Prisma / NextAuth imports) */

export type AppRole = "SUPER_ADMIN" | "ADMIN" | "USER";

export function dashboardPathForRole(role: string) {
  switch (role) {
    case "SUPER_ADMIN":
      return "/dashboard/super-admin";
    case "ADMIN":
      return "/dashboard/admin";
    case "USER":
      return "/dashboard/user";
    default:
      return "/login";
  }
}

import { getToken } from "next-auth/jwt";
import { NextRequest, NextResponse } from "next/server";
import { dashboardPathForRole } from "@/lib/dashboard-path";

/**
 * Edge middleware must NOT import next-auth/middleware or @/lib/auth-options —
 * those pull in openid-client and break the Edge runtime.
 */
export async function middleware(req: NextRequest) {
  const path = req.nextUrl.pathname;

  const token = await getToken({
    req,
    secret: process.env.NEXTAUTH_SECRET,
  });

  if (!token) {
    return NextResponse.redirect(new URL("/login", req.url));
  }

  const role = token.role as string;
  const home = dashboardPathForRole(role);

  if (path === "/dashboard") {
    return NextResponse.redirect(new URL(home, req.url));
  }

  if (path.startsWith("/dashboard/super-admin") && role !== "SUPER_ADMIN") {
    return NextResponse.redirect(new URL(home, req.url));
  }
  if (path.startsWith("/dashboard/admin")) {
    if (role !== "ADMIN" && role !== "SUPER_ADMIN") {
      return NextResponse.redirect(new URL(home, req.url));
    }
  }
  if (path.startsWith("/dashboard/user") && role !== "USER") {
    return NextResponse.redirect(new URL(home, req.url));
  }

  return NextResponse.next();
}

export const config = {
  matcher: [
    "/dashboard/:path*",
    "/api/entries/:path*",
    "/api/users/:path*",
    "/api/messages/:path*",
    "/api/stats/:path*",
  ],
};

